  1→import domtoimage from 'dom-to-image';
  2→
  3→/**
  4→ * Takes a screenshot of the specified element
  5→ * @param {React.RefObject} widgetContainerRef - Reference to the widget container
  6→ * @param {Function} showToast - Callback function to show a toast message
  7→ */
  8→export function takeScreenshot(widgetContainerRef, showToast) {
  9→  // Handle both direct refs and ref objects
 10→  const element = widgetContainerRef.current || 
 11→                 (typeof widgetContainerRef === 'object' && widgetContainerRef.nodeType ? widgetContainerRef : null);
 12→  
 13→  if (!element) {
 14→    console.error('Invalid reference provided to takeScreenshot');
 15→    if (typeof showToast === 'function') {
 16→      showToast("Failed to capture screenshot: Invalid element reference");
 17→    }
 18→    return;
 19→  }
 20→
 21→  // Take screenshot with simple configuration, no need for complex image processing
 22→  domtoimage.toBlob(element, {
 23→    quality: 1.0,
 24→    bgcolor: 'transparent',
 25→    style: {
 26→      'transform': 'none',
 27→      'transform-origin': 'none'
 28→    }
 29→  })
 30→  .then(function (blob) {
 31→    // Try to copy to clipboard
 32→    if (navigator.clipboard && window.ClipboardItem) {
 33→      try {
 34→        const item = new ClipboardItem({'image/png': blob});
 35→        navigator.clipboard.write([item])
 36→          .then(() => {
 37→            if (typeof showToast === 'function') {
 38→              showToast("Screenshot copied to clipboard!");
 39→            }
 40→          })
 41→          .catch(error => {
 42→            console.error('Error copying to clipboard:', error);
 43→            downloadFromBlob(blob);
 44→            if (typeof showToast === 'function') {
 45→              showToast("Clipboard not supported, image downloaded instead.");
 46→            }
 47→          });
 48→      } catch (error) {
 49→        console.error('Error with clipboard:', error);
 50→        downloadFromBlob(blob);
 51→        if (typeof showToast === 'function') {
 52→          showToast("Clipboard error, image downloaded instead.");
 53→        }
 54→      }
 55→    } else {
 56→      // For browsers that don't support ClipboardItem
 57→      downloadFromBlob(blob);
 58→      if (typeof showToast === 'function') {
 59→        showToast("Clipboard not supported, image downloaded instead.");
 60→      }
 61→    }
 62→  })
 63→  .catch(function (error) {
 64→    console.error('Screenshot error:', error);
 65→    if (typeof showToast === 'function') {
 66→      showToast("Failed to capture screenshot. Check console for details.");
 67→    }
 68→  });
 69→}
 70→
 71→/**
 72→ * Download a blob as an image file
 73→ */
 74→function downloadFromBlob(blob) {
 75→  const url = URL.createObjectURL(blob);
 76→  const a = document.createElement('a');
 77→  a.style.display = 'none';
 78→  a.href = url;
 79→  a.download = `screenshot_${new Date().toISOString()}.png`;
 80→  document.body.appendChild(a);
 81→  a.click();
 82→  
 83→  // Clean up
 84→  setTimeout(() => {
 85→    document.body.removeChild(a);
 86→    URL.revokeObjectURL(url);
 87→  }, 100);
 88→}
 89→
 90→/**
 91→ * Convert a blob to a data URL
 92→ */
 93→function blobToDataURL(blob, callback) {
 94→  const reader = new FileReader();
 95→  reader.onload = function(e) {
 96→    callback(e.target.result);
 97→  };
 98→  reader.readAsDataURL(blob);
 99→}
100→
101→function downloadImage(dataUrl, elementId) {
102→  const fileName = elementId ? `${elementId}.png` : `screenshot_${new Date().toISOString()}.png`;
103→  const a = document.createElement('a');
104→  a.href = dataUrl;
105→  a.download = fileName;
106→  a.style.display = 'none';
107→  document.body.appendChild(a);
108→  a.click();
109→  document.body.removeChild(a);
110→}
111→
112→function copyToClipboardModern(dataUrl) {
113→  return new Promise((resolve, reject) => {
114→    fetch(dataUrl)
115→      .then(res => res.blob())
116→      .then(blob => {
117→        const item = new ClipboardItem({'image/png': blob});
118→        navigator.clipboard.write([item]).then(resolve, reject);
119→      })
120→      .catch(reject);
121→  });
122→}
