 3→interface ChartTooltipProps {
 4→	active?: boolean;
 5→	// biome-ignore lint/suspicious/noExplicitAny: recharts payload type is complex and varies by chart
 6→	payload?: ReadonlyArray<any>;
 7→	label?: string | number;
 8→	nameFormatter?: (name: string) => string;
 9→	valueFormatter?: (value: number, name: string) => string;
10→	showTotal?: boolean;
11→}
12→
13→export function ChartTooltip({
14→	active,
15→	payload,
16→	label,
17→	nameFormatter,
18→	valueFormatter,
19→	showTotal = true,
20→}: ChartTooltipProps) {
21→	const { tooltipBg, tooltipBorder } = useChartTheme();
22→
23→	if (!active || !payload || payload.length === 0) return null;
24→
25→	const visibleItems = payload.filter((item) => item.value !== 0);
26→	if (visibleItems.length === 0) return null;
27→
28→	const total = visibleItems.reduce((sum, item) => sum + item.value, 0);
29→
30→	const formatValue = (value: number, name: string): string => {
31→		if (valueFormatter) return valueFormatter(value, name);
32→		return value.toLocaleString();
33→	};
34→
35→	return (
36→		<div
37→			className="rounded-lg shadow-lg p-3 min-w-[180px]"
38→			style={{
39→				backgroundColor: tooltipBg,
40→				border: `1px solid ${tooltipBorder}`,
41→			}}
42→		>
43→			{label && (
44→				<div className="text-xs font-semibold text-foreground mb-2">
45→					{label}
46→				</div>
47→			)}
48→			<div className="space-y-0.5">
49→				{visibleItems.map((item) => {
50→					const displayName = nameFormatter
51→						? nameFormatter(item.name)
52→						: item.name;
53→					return (
54→						<div key={item.name} className="flex items-center gap-2 py-0.5">
55→							<div
56→								className="w-2 h-2 rounded-full flex-shrink-0"
57→								style={{ backgroundColor: item.color ?? item.fill }}
58→							/>
59→							<span className="text-xs text-foreground flex-1">
60→								{displayName}
61→							</span>
62→							<span className="text-xs font-semibold text-foreground">
63→								{formatValue(item.value, item.name)}
64→							</span>
65→						</div>
66→					);
67→				})}
68→			</div>
69→			{showTotal && visibleItems.length > 1 && (
70→				<div className="pt-1.5 mt-1.5 border-t border-border flex justify-between text-xs font-semibold text-foreground">
71→					<span>Total</span>
72→					<span>{formatValue(total, "total")}</span>
