 38→const CHART_COLORS = [
 39→	"#3b82f6",
 40→	"#10b981",
 41→	"#f59e0b",
 42→	"#8b5cf6",
 43→	"#ef4444",
 44→	"#06b6d4",
 45→	"#f97316",
 46→	"#ec4899",
 47→	"#14b8a6",
 48→	"#6366f1",
 49→];
