 51→function formatMetricLabel(metric: string): string {
 52→	const labelMap: Record<string, string> = {
 53→		session_count: "Session Count",
 54→		avg_duration: "Avg Duration (min)",
 55→		total_duration: "Total Duration (hours)",
 56→		avg_interactions: "Avg Interactions",
 57→		total_interactions: "Total Interactions",
 58→		avg_response_time: "Avg Response Time (sec)",
 59→		median_response_time: "Median Response Time (sec)",
 60→		avg_tokens: "Avg Tokens",
 61→		total_tokens: "Total Tokens",
 62→		avg_success_score: "Avg Success Score",
 63→		avg_errors: "Avg Errors",
 64→		total_errors: "Total Errors",
 65→	};
 66→	return labelMap[metric] || metric;
 67→}
 68→
 69→function formatDimensionValue(
 70→	value: string,
 71→	dimension: string,
 72→	userMap?: Record<string, string>,
 73→): string {
 74→	if (
 75→		dimension === "has_commit" ||
 76→		dimension === "used_plan_mode" ||
 77→		dimension === "used_skills" ||
 78→		dimension === "used_slash_commands" ||
 79→		dimension === "used_subagents"
 80→	) {
 81→		return value === "1" ? "Yes" : "No";
 82→	}
 83→
 84→	if (dimension === "project_path") {
 85→		const parts = value.split("/");
 86→		return parts[parts.length - 1] || value;
 87→	}
 88→
 89→	if (dimension === "user_id") {
 90→		return formatUsername(value, userMap);
 91→	}
 92→
 93→	return value;
 94→}
