 96→export const DimensionAnalysisChart = memo(function DimensionAnalysisChart({
 97→	data,
 98→	dimension,
 99→	metric,
100→	split_by,
101→	showPercentage = false,
102→	userMap,
103→}: DimensionAnalysisChartProps) {
104→	const { gridStroke, axisStroke } = useChartTheme();
105→	const [hiddenSeries, setHiddenSeries] = useState<Set<string>>(new Set());
106→	const toggleSeries = (key: string) =>
107→		setHiddenSeries((prev) => {
108→			const next = new Set(prev);
109→			next.has(key) ? next.delete(key) : next.add(key);
110→			return next;
111→		});
112→
113→	const { chartData, dataKeys } = useMemo(() => {
114→		if (!data || data.length === 0) {
115→			return { chartData: [], dataKeys: [] };
116→		}
117→
118→		let chartData: Record<string, unknown>[] = [];
119→		let dataKeys: string[] = [];
120→
121→		if (split_by && data[0].split_values) {
122→			const allSplitValues = new Set<string>();
123→			for (const item of data) {
124→				if (item.split_values) {
125→					for (const key of Object.keys(item.split_values)) {
126→						allSplitValues.add(key);
127→					}
128→				}
129→			}
130→			const rawSplitKeys = Array.from(allSplitValues);
131→			// Sort split keys by total raw value descending
132→			const splitKeyTotals = new Map<string, number>();
133→			for (const item of data) {
134→				for (const key of rawSplitKeys) {
135→					splitKeyTotals.set(
136→						key,
137→						(splitKeyTotals.get(key) ?? 0) + (item.split_values?.[key] || 0),
138→					);
139→				}
140→			}
141→			rawSplitKeys.sort(
142→				(a, b) => (splitKeyTotals.get(b) ?? 0) - (splitKeyTotals.get(a) ?? 0),
143→			);
144→			// Map raw split keys to display names (e.g. user IDs → names)
145→			const splitKeyDisplayMap: Record<string, string> = {};
146→			for (const key of rawSplitKeys) {
147→				splitKeyDisplayMap[key] = formatDimensionValue(key, split_by, userMap);
148→			}
149→			dataKeys = rawSplitKeys.map((key) => splitKeyDisplayMap[key]);
150→
151→			chartData = data.map((item) => {
152→				const row: Record<string, unknown> = {
153→					name: formatDimensionValue(item.dimension_value, dimension, userMap),
154→					_fullName: item.dimension_value,
155→					_total: 0,
156→					_originalValues: {} as Record<string, number>,
157→				};
158→				const origValues = row._originalValues as Record<string, number>;
159→				let total = 0;
160→				for (const key of rawSplitKeys) {
161→					const displayKey = splitKeyDisplayMap[key];
162→					const val = item.split_values?.[key] || 0;
163→					origValues[displayKey] = val;
164→					total += val;
165→				}
166→				row._total = total;
167→
168→				if (showPercentage && total > 0) {
169→					for (const key of rawSplitKeys) {
170→						const displayKey = splitKeyDisplayMap[key];
171→						row[displayKey] = (origValues[displayKey] / total) * 100;
172→					}
173→				} else {
174→					for (const key of rawSplitKeys) {
175→						const displayKey = splitKeyDisplayMap[key];
176→						row[displayKey] = origValues[displayKey];
177→					}
178→				}
179→
180→				return row;
181→			});
182→
183→			chartData.sort((a, b) => (b._total as number) - (a._total as number));
184→		} else {
185→			dataKeys = [formatMetricLabel(metric)];
186→			chartData = data.map((item) => ({
187→				name: formatDimensionValue(item.dimension_value, dimension, userMap),
188→				_fullName: item.dimension_value,
189→				[formatMetricLabel(metric)]: item.metric_value || 0,
190→			}));
191→
192→			chartData.sort(
193→				(a, b) =>
194→					(b[formatMetricLabel(metric)] as number) -
195→					(a[formatMetricLabel(metric)] as number),
196→			);
197→		}
198→
199→		return { chartData, dataKeys };
200→	}, [data, dimension, metric, split_by, showPercentage, userMap]);
201→
202→	if (!data || data.length === 0) {
203→		return (
204→			<div className="flex items-center justify-center h-64 text-muted">
205→				No data available for the selected dimension and metric
206→			</div>
207→		);
208→	}
209→
210→	const renderTooltip = (props: Record<string, unknown>) => {
211→		const { active, payload, label } = props;
212→		if (!active || !Array.isArray(payload) || payload.length === 0) return null;
213→
214→		const payloadData = (payload[0] as Record<string, unknown>)?.payload as
215→			| Record<string, unknown>
216→			| undefined;
217→		const fullName = (payloadData?._fullName || label) as string | undefined;
218→		const originalValues = payloadData?._originalValues as
219→			| Record<string, number>
220→			| undefined;
221→
222→		// Build normalized items for ChartTooltip using raw values
223→		const normalizedPayload = payload
224→			.filter((entry: Record<string, unknown>) => {
225→				const rawVal =
226→					originalValues?.[entry.name as string] ?? (entry.value as number);
227→				return rawVal !== 0;
228→			})
229→			.map((entry: Record<string, unknown>) => ({
230→				name: entry.name as string,
231→				value:
232→					originalValues?.[entry.name as string] ?? (entry.value as number),
233→				color: (entry.color ?? entry.fill) as string,
234→			}));
235→
236→		const valueFormatter =
237→			showPercentage && originalValues
238→				? (v: number, name: string) => {
239→						const pct = payload.find(
240→							(e: Record<string, unknown>) => e.name === name,
241→						);
242→						const pctVal = pct ? (pct.value as number) : 0;
243→						return `${formatNumberWithCommas(v)} (${pctVal.toFixed(1)}%)`;
244→					}
245→				: (v: number) => formatNumberWithCommas(v);
246→
247→		return (
248→			<ChartTooltip
249→				active={true}
250→				payload={normalizedPayload}
251→				label={fullName}
252→				valueFormatter={valueFormatter}
253→				showTotal={!showPercentage}
254→			/>
255→		);
256→	};
257→
258→	return (
259→		<div className="w-full">
260→			<ResponsiveContainer width="100%" height={400}>
261→				<BarChart
262→					data={chartData}
263→					layout="vertical"
264→					margin={{ top: 20, right: 30, left: 10, bottom: 20 }}
265→				>
266→					<CartesianGrid strokeDasharray="3 3" stroke={gridStroke} />
267→					<XAxis
268→						type="number"
269→						className="text-xs"
270→						tick={{ fill: axisStroke }}
271→						tickFormatter={
272→							showPercentage && split_by
273→								? (value) => `${value.toFixed(0)}%`
274→								: formatCompactNumber
275→						}
276→						domain={showPercentage && split_by ? [0, 100] : undefined}
277→						label={{
278→							value:
279→								showPercentage && split_by
280→									? "Percentage (%)"
281→									: formatMetricLabel(metric),
282→							position: "insideBottom",
283→							offset: -10,
284→							style: { textAnchor: "middle", fill: axisStroke },
285→						}}
286→					/>
287→					<YAxis
288→						type="category"
289→						dataKey="name"
290→						width={150}
291→						className="text-xs"
292→						tick={{ fill: axisStroke, fontSize: 12 }}
293→						interval={0}
294→					/>
295→					<Tooltip
296→						content={(props) => renderTooltip(props as Record<string, unknown>)}
297→					/>
298→					{split_by && (
299→						<Legend
300→							layout="vertical"
301→							align="right"
302→							verticalAlign="top"
303→							width={160}
304→							content={({ payload }) => (
305→								<ChartLegend
306→									payload={payload}
307→									hiddenSeries={hiddenSeries}
308→									onToggle={toggleSeries}
309→								/>
310→							)}
311→						/>
312→					)}
313→					{split_by ? (
314→						dataKeys.map((key, index) => (
315→							<Bar
316→								key={key}
317→								dataKey={key}
318→								stackId="stack"
319→								hide={hiddenSeries.has(key)}
320→								fill={CHART_COLORS[index % CHART_COLORS.length]}
321→							/>
322→						))
323→					) : (
324→						<Bar dataKey={formatMetricLabel(metric)} fill="#3b82f6" />
325→					)}
326→				</BarChart>
327→			</ResponsiveContainer>
328→		</div>
329→	);
330→});
