 46→const COLORS = [
 47→	"#ef4444",
 48→	"#f59e0b",
 49→	"#10b981",
 50→	"#3b82f6",
 51→	"#8b5cf6",
 52→	"#ec4899",
 53→	"#06b6d4",
 54→	"#14b8a6",
 55→	"#f97316",
 56→	"#6366f1",
 57→	"#84cc16",
 58→	"#a855f7",
 59→	"#f43f5e",
 60→	"#0ea5e9",
 61→];
 62→
 63→const METRIC_LABELS: Record<string, string> = {
 64→	avg_errors_per_interaction: "Avg Errors per Interaction",
 65→	avg_errors_per_session: "Avg Errors per Session",
 66→	total_errors: "Total Errors",
 67→};
 68→
 69→const SPLIT_LABELS: Record<string, string> = {
 70→	project_path: "by Project",
 71→	user_id: "by Developer",
 72→	model: "by Model",
