 74→
 75→export function ErrorTrendChart({
 76→	data,
 77→	metric,
 78→	splitBy,
 79→	onMetricChange,
 80→	onSplitByChange,
 81→	userMap,
 82→}: ErrorTrendChartProps) {
 83→	const { gridStroke } = useChartTheme();
 84→	const [hiddenSeries, setHiddenSeries] = useState<Set<string>>(new Set());
 85→	const toggleSeries = (key: string) =>
 86→		setHiddenSeries((prev) => {
 87→			const next = new Set(prev);
 88→			next.has(key) ? next.delete(key) : next.add(key);
 89→			return next;
 90→		});
 91→
 92→	const stableColorOrder = useMemo(() => {
 93→		if (data.length === 0) return [];
 94→		const totals = new Map<string, number>();
 95→		for (const item of data) {
 96→			totals.set(
 97→				item.dimension,
 98→				(totals.get(item.dimension) ?? 0) + item.total_errors,
 99→			);
100→		}
101→		return [...totals.entries()]
102→			.sort((a, b) => b[1] - a[1])
103→			.slice(0, MAX_SERIES)
104→			.map(([k]) => k);
105→	}, [data]);
106→
107→	const colorMap = useMemo(() => {
108→		const map = new Map<string, string>();
109→		for (let i = 0; i < stableColorOrder.length; i++) {
110→			map.set(stableColorOrder[i], COLORS[i % COLORS.length]);
111→		}
112→		map.set("Other", OTHER_COLOR);
113→		return map;
114→	}, [stableColorOrder]);
115→
116→	const { seriesKeys, chartData } = useMemo(() => {
117→		if (data.length === 0) return { seriesKeys: [], chartData: [] };
118→
119→		// Compute totals per dimension to rank and cap at MAX_SERIES
120→		const dimTotals = new Map<string, number>();
121→		for (const item of data) {
122→			dimTotals.set(
123→				item.dimension,
124→				(dimTotals.get(item.dimension) ?? 0) + ((item[metric] as number) ?? 0),
125→			);
126→		}
127→
128→		const sortedDims = Array.from(dimTotals.entries()).sort(
129→			(a, b) => b[1] - a[1],
130→		);
131→		const topDims = sortedDims.slice(0, MAX_SERIES).map(([k]) => k);
132→		const topDimsSet = new Set(topDims);
133→		// Only add "Other" for total_errors (summable); avg metrics are not meaningful to sum
134→		const hasOther =
135→			metric === "total_errors" && sortedDims.length > MAX_SERIES;
136→		const seriesKeys = hasOther ? [...topDims, "Other"] : topDims;
137→
138→		// Build full date range
139→		const allDates = Array.from(new Set(data.map((item) => item.date))).sort();
140→		const minDate = new Date(allDates[0]);
141→		const maxDate = new Date(allDates[allDates.length - 1]);
142→		const dateRange: string[] = [];
143→		for (let d = new Date(minDate); d <= maxDate; d.setDate(d.getDate() + 1)) {
144→			dateRange.push(d.toISOString().split("T")[0]);
145→		}
146→
147→		const dateMap = new Map<string, Record<string, unknown>>();
148→		for (const dateKey of dateRange) {
149→			const dateData: Record<string, unknown> = {
150→				date: dateKey,
151→				displayDate: new Date(dateKey).toLocaleDateString("en-US", {
152→					month: "short",
153→					day: "numeric",
154→				}),
155→			};
156→			for (const key of seriesKeys) {
157→				dateData[key] = 0;
158→			}
