160→		}
161→
162→		for (const item of data) {
163→			const dateData = dateMap.get(item.date);
164→			if (!dateData) continue;
165→			if (topDimsSet.has(item.dimension)) {
166→				dateData[item.dimension] = item[metric];
167→			} else if (hasOther) {
168→				dateData.Other =
169→					((dateData.Other as number) ?? 0) + ((item[metric] as number) ?? 0);
170→			}
171→		}
172→
173→		return {
174→			seriesKeys,
175→			chartData: Array.from(dateMap.values()).sort((a, b) =>
