214→					>
215→						<SelectTrigger className="w-56">
216→							<SelectValue />
217→						</SelectTrigger>
218→						<SelectContent>
219→							{Object.entries(METRIC_LABELS).map(([key, label]) => (
220→								<SelectItem key={key} value={key}>
221→									{label}
222→								</SelectItem>
