 21→import { ChartLegend } from "./ChartLegend";
 22→import { ChartTooltip } from "./ChartTooltip";
 23→
 24→const MAX_SERIES = 14;
 25→const OTHER_COLOR = "#9ca3af";
 26→
 27→interface LearningsTrendChartProps {
 28→	data: Record<string, string | number>[];
 29→	splitBy: "user_id" | "repository";
 30→	onSplitByChange: (splitBy: "user_id" | "repository") => void;
 31→	userMap?: Record<string, string>;
 32→}
 33→
 34→const COLORS = [
 35→	"#3b82f6",
 36→	"#10b981",
 37→	"#f59e0b",
 38→	"#8b5cf6",
 39→	"#ef4444",
 40→	"#06b6d4",
 41→	"#ec4899",
 42→	"#14b8a6",
 43→	"#f97316",
 44→	"#6366f1",
 45→	"#84cc16",
 46→	"#a855f7",
 47→	"#f43f5e",
 48→	"#0ea5e9",
 49→];
 50→
 51→export function LearningsTrendChart({
 52→	data,
 53→	splitBy,
 54→	onSplitByChange,
 55→	userMap,
 56→}: LearningsTrendChartProps) {
 57→	const { gridStroke } = useChartTheme();
 58→	const [isCumulative, setIsCumulative] = useState(true);
 59→	const [hiddenSeries, setHiddenSeries] = useState<Set<string>>(new Set());
 60→	const toggleSeries = (key: string) =>
 61→		setHiddenSeries((prev) => {
 62→			const next = new Set(prev);
 63→			next.has(key) ? next.delete(key) : next.add(key);
 64→			return next;
 65→		});
 66→
 67→	// All series keys from the data
 68→	const allSeriesKeys = useMemo(() => {
 69→		if (data.length === 0) return [];
 70→		const keys = new Set<string>();
 71→		for (const item of data) {
 72→			for (const key of Object.keys(item)) {
 73→				if (key !== "date") keys.add(key);
 74→			}
 75→		}
 76→		return Array.from(keys).sort();
 77→	}, [data]);
 78→
 79→	// Cap at MAX_SERIES, rest → "Other"
 80→	const { seriesKeys, hasOther } = useMemo(() => {
 81→		if (allSeriesKeys.length <= MAX_SERIES) {
 82→			return { seriesKeys: allSeriesKeys, hasOther: false };
 83→		}
 84→		// Rank by total value across all dates
 85→		const totals = new Map<string, number>();
 86→		for (const item of data) {
 87→			for (const key of allSeriesKeys) {
 88→				totals.set(key, (totals.get(key) ?? 0) + ((item[key] as number) || 0));
 89→			}
 90→		}
 91→		const sorted = Array.from(totals.entries()).sort((a, b) => b[1] - a[1]);
 92→		return {
 93→			seriesKeys: sorted.slice(0, MAX_SERIES).map(([k]) => k),
 94→			hasOther: true,
 95→		};
 96→	}, [allSeriesKeys, data]);
 97→
 98→	const filledData = useMemo(() => {
 99→		if (data.length === 0) return [];
100→
101→		const existingDates = Array.from(
102→			new Set(data.map((d) => d.date as string)),
103→		).sort();
104→		const minDate = new Date(existingDates[0]);
105→		const maxDate = new Date(existingDates[existingDates.length - 1]);
106→		const dateRange: string[] = [];
107→		for (let d = new Date(minDate); d <= maxDate; d.setDate(d.getDate() + 1)) {
108→			dateRange.push(d.toISOString().split("T")[0]);
109→		}
110→
111→		const dataByDate = new Map(data.map((item) => [item.date as string, item]));
112→		const topKeysSet = new Set(seriesKeys);
113→
114→		return dateRange.map((dateKey) => {
115→			const item = dataByDate.get(dateKey);
116→			const entry: Record<string, string | number> = { date: dateKey };
117→			for (const key of seriesKeys) {
118→				entry[key] = item ? (item[key] as number) || 0 : 0;
119→			}
120→			if (hasOther) {
121→				entry.Other = item
122→					? allSeriesKeys
123→							.filter((k) => !topKeysSet.has(k))
124→							.reduce((sum, k) => sum + ((item[k] as number) || 0), 0)
125→					: 0;
126→			}
127→			return entry;
128→		});
129→	}, [data, seriesKeys, allSeriesKeys, hasOther]);
130→
131→	const displayKeys = hasOther ? [...seriesKeys, "Other"] : seriesKeys;
132→
133→	const chartData = useMemo(() => {
134→		if (!isCumulative) {
135→			return filledData.map((item) => ({
136→				...item,
137→				displayDate: new Date(item.date as string).toLocaleDateString("en-US", {
138→					month: "short",
139→					day: "numeric",
140→				}),
141→			}));
142→		}
143→
144→		const cumulativeData = [];
145→		const runningTotals: Record<string, number> = {};
146→		for (const key of displayKeys) {
147→			runningTotals[key] = 0;
148→		}
149→
150→		for (const item of filledData) {
151→			const cumulativeItem: Record<string, unknown> = {
152→				date: item.date,
153→				displayDate: new Date(item.date as string).toLocaleDateString("en-US", {
154→					month: "short",
155→					day: "numeric",
156→				}),
157→			};
158→			for (const key of displayKeys) {
159→				runningTotals[key] += (item[key] as number) || 0;
160→				cumulativeItem[key] = runningTotals[key];
161→			}
162→			cumulativeData.push(cumulativeItem);
163→		}
164→
165→		return cumulativeData;
166→	}, [filledData, isCumulative, displayKeys]);
167→
168→	const getDisplayName = (key: string): string => {
169→		if (key === "Other") return "Other";
170→		if (splitBy === "user_id" && userMap) {
171→			return userMap[key] || `${key.substring(0, 12)}...`;
172→		}
173→		return key;
174→	};
175→
176→	return (
177→		<div className="space-y-4">
178→			<div className="flex flex-wrap items-center justify-end gap-4">
179→				<div className="flex items-center gap-2">
180→					<Select
181→						value={splitBy}
182→						onValueChange={(v) =>
183→							onSplitByChange(v as "user_id" | "repository")
184→						}
185→					>
186→						<SelectTrigger className="w-40">
187→							<SelectValue />
188→						</SelectTrigger>
189→						<SelectContent>
190→							<SelectItem value="user_id">by Developer</SelectItem>
191→							<SelectItem value="repository">by Repository</SelectItem>
192→						</SelectContent>
193→					</Select>
194→				</div>
195→
196→				<div className="flex items-center gap-2">
197→					<label
198→						htmlFor="cumulative-toggle"
199→						className="text-sm font-medium text-muted cursor-pointer"
200→					>
201→						Cumulative
202→					</label>
203→					<Switch
204→						id="cumulative-toggle"
205→						checked={isCumulative}
206→						onCheckedChange={setIsCumulative}
207→					/>
208→				</div>
209→			</div>
210→
211→			<ResponsiveContainer width="100%" height={400}>
212→				<BarChart
213→					data={chartData}
214→					margin={{ top: 10, right: 0, left: 0, bottom: 0 }}
215→				>
216→					<CartesianGrid strokeDasharray="3 3" stroke={gridStroke} />
217→					<XAxis
218→						dataKey="displayDate"
219→						tick={{ fontSize: 12 }}
220→						angle={-45}
221→						textAnchor="end"
222→						height={80}
223→						tickMargin={8}
224→					/>
225→					<YAxis tick={{ fontSize: 12 }} />
226→					<Tooltip
227→						content={(props) => (
228→							<ChartTooltip
229→								{...props}
230→								nameFormatter={getDisplayName}
231→								valueFormatter={(v) => v.toLocaleString()}
232→							/>
233→						)}
234→					/>
235→					<Legend
236→						layout="vertical"
237→						align="right"
238→						verticalAlign="top"
239→						width={160}
240→						content={({ payload }) => (
241→							<ChartLegend
242→								payload={payload}
243→								formatter={getDisplayName}
244→								hiddenSeries={hiddenSeries}
245→								onToggle={toggleSeries}
246→							/>
247→						)}
248→					/>
249→					{displayKeys.map((key, index) => (
250→						<Bar
251→							key={key}
252→							dataKey={key}
253→							name={key}
254→							stackId="1"
255→							hide={hiddenSeries.has(key)}
256→							fill={
257→								key === "Other" ? OTHER_COLOR : COLORS[index % COLORS.length]
258→							}
259→						/>
260→					))}
261→				</BarChart>
262→			</ResponsiveContainer>
263→
264→			{displayKeys.length === 0 && (
265→				<div className="text-center text-sm text-muted py-4">
266→					No data available for the selected time period
267→				</div>
268→			)}
269→		</div>
270→	);
271→}
