 33→const getTimezoneOptions = () => {
 34→  const userTimezone = moment.tz.guess();
 35→  const allTimezones = moment.tz.names().map((tz) => ({
 36→    key: tz,
 37→    label: `${tz} (${moment.tz(tz).format("Z")})`,
 38→    value: tz,
 39→  }));
 40→
 41→  // If we have a detected user timezone, put it first
 42→  if (userTimezone) {
 43→    const userTzOption = {
 44→      key: userTimezone,
 45→      label: `${userTimezone} (${moment.tz(userTimezone).format("Z")}) - Your Local Time`,
 46→      value: userTimezone,
 47→    };
 48→    
 49→    // Remove user timezone from the full list to avoid duplicates
 50→    const otherTimezones = allTimezones.filter(tz => tz.key !== userTimezone);
 51→    
 52→    return [userTzOption, ...otherTimezones];
 53→  }
 54→  
 55→  return allTimezones;
 56→};
