## Pattern Examples: Share / Export / Social Media in the Lenses Codebase

### Pattern 1: Screenshot to Clipboard + Twitter Intent (dom-to-image)

**Found in**: `/Users/alvaro/Workspace/numia/lenses/apps/lenses/data/ScreenShot.js:1-123`

This is the core screenshot utility. It uses the `dom-to-image` library to capture a DOM element as a PNG blob, copies it to the clipboard, and falls back to downloading the image if clipboard is unsupported.

```javascript
import domtoimage from 'dom-to-image';

export function takeScreenshot(widgetContainerRef, showToast) {
  const element = widgetContainerRef.current || 
                 (typeof widgetContainerRef === 'object' && widgetContainerRef.nodeType ? widgetContainerRef : null);

  if (!element) {
    console.error('Invalid reference provided to takeScreenshot');
    if (typeof showToast === 'function') {
      showToast("Failed to capture screenshot: Invalid element reference");
    }
    return;
  }

  domtoimage.toBlob(element, {
    quality: 1.0,
    bgcolor: 'transparent',
    style: {
      'transform': 'none',
      'transform-origin': 'none'
    }
  })
  .then(function (blob) {
    if (navigator.clipboard && window.ClipboardItem) {
      try {
        const item = new ClipboardItem({'image/png': blob});
        navigator.clipboard.write([item])
          .then(() => {
            if (typeof showToast === 'function') {
              showToast("Screenshot copied to clipboard!");
            }
          })
          .catch(error => {
            console.error('Error copying to clipboard:', error);
            downloadFromBlob(blob);
            if (typeof showToast === 'function') {
              showToast("Clipboard not supported, image downloaded instead.");
            }
          });
      } catch (error) {
        console.error('Error with clipboard:', error);
        downloadFromBlob(blob);
        if (typeof showToast === 'function') {
          showToast("Clipboard error, image downloaded instead.");
        }
      }
    } else {
      downloadFromBlob(blob);
      if (typeof showToast === 'function') {
        showToast("Clipboard not supported, image downloaded instead.");
      }
    }
  })
  .catch(function (error) {
    console.error('Screenshot error:', error);
    if (typeof showToast === 'function') {
      showToast("Failed to capture screenshot. Check console for details.");
    }
  });
}

function downloadFromBlob(blob) {
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.style.display = 'none';
  a.href = url;
  a.download = `screenshot_${new Date().toISOString()}.png`;
  document.body.appendChild(a);
  a.click();
  setTimeout(() => {
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  }, 100);
}
```

**Key aspects**:
- Library: `dom-to-image` (`^2.6.0`) declared in `apps/lenses/package.json:32`
- Captures a DOM element via `domtoimage.toBlob()`
- Primary path: copy PNG to clipboard via `ClipboardItem` API
- Fallback path: download as `.png` file via dynamic `<a>` element
- Additional unused helpers: `blobToDataURL`, `downloadImage`, `copyToClipboardModern`
- Safari is excluded from the screenshot/tweet flow (checked via `isSafari` context)

