  6→/**
  7→ * WidgetWrapper Component
  8→ * 
  9→ * This component wraps the Widget component, providing responsive sizing and error boundary.
 10→ * 
 11→ * @param {Object} props
 12→ * @param {string} type - The type of widget (e.g., "chart", "table", "kpiBar")
 13→ * @param {string} title - The title of the widget
 14→ * @param {string} id - Unique identifier for the widget
 15→ * @param {string} rowHeight - Height of the widget ("auto", "small", "medium", "large")
 16→ * @param {number} widgetWidth - Width of the widget in grid columns (1-12)
 17→ * @param {Array} timeFilter - Time filter options for the widget
 18→ * @param {string} contentSearch - Search string for widget content
 19→ * @param {string} source - Data source URL for the widget
 20→ * @param {string} pageId - ID of the page containing the widget
 21→ * @param {string} timeScaleAggregate - Time scale aggregation method
 22→ * @param {string} yScaleType - Y-axis scale type
 23→ * @param {boolean} allowTableView - Whether to show table view toggle
 24→ * @param {string} timeAggregationMethod - Method for time aggregation
 25→ * @param {boolean} defaultCumulated - Whether data should be cumulated by default
 26→ * @param {Object} contentFilter - Content filter options
 27→ * @param {boolean} yStacked - Whether Y-axis should be stacked
 28→ * @param {boolean} defaultLogScale - Whether to use log scale by default
 29→ * @param {boolean} useUnitToggle - Whether to show unit toggle
 30→ * @param {boolean} allowCumulation - Whether to allow data cumulation
 31→ * @param {boolean} filled - Whether the chart should be filled
 32→ * @param {string} defaultUnit - Default unit for the widget
 33→ * @param {boolean} hideChartTypeToggle - Whether to hide chart type toggle
 34→ * @param {Array} nonGradientColors - Colors to use instead of gradients
 35→ * @param {string} multipleSelectVariant - Variant for multiple select
 36→ * @param {string} defaultTimeFrame - Default time frame for the widget
 37→ * @param {boolean} timeAggregationByBackend - Whether time aggregation is done by backend
 38→ * @param {string} defaultPeriod - Default period for the widget
 39→ * @param {string} defaultFlattenKey - Default key for flattening data
 40→ * @param {Array} hiddenKeys - Keys to hide in the widget
 41→ * @param {boolean} showSingleKey - Whether to show only a single key
 42→ */
 43→function WidgetWrapper(props) {
 44→  const { isPhone, isMobile, isTablet, windowWidth, windowHeight } = useContext(AppContext);
 45→  const widgetContainerRef = useRef();
 46→  const { type, id, rowHeight, widgetWidth } = props;
 47→
 48→  const getBodyWidthClass = () => {
 49→    if (isMobile) return "w-full";
 50→    if (isTablet) {
 51→      if (type === "kpiBar") return "col-span-12";
 52→      if (id.includes("whale_tracker")) return "col-span-12";
 53→      if (id === "whale_tracker_xl") return "col-span-12";
 54→      if (id === "activity_tracker") return "col-span-6";
 55→      return "col-span-6";
 56→    }
 57→    return `col-span-${widgetWidth}`;
 58→  };
 59→
 60→  const getBodyHeightClass = () => {
 61→    let baseClass = "";
 62→    switch (rowHeight) {
 63→      case "auto":
 64→        baseClass = "h-stretch";
 65→        break;
 66→      case "small":
 67→        baseClass = "h-[34vh]";
 68→        break;
 69→      case "medium":
 70→        baseClass = "h-[45vh]";
 71→        break;
 72→      case "large":
 73→        baseClass = "h-[85vh]";
 74→        break;
 75→      default:
 76→        baseClass = "h-[45vh]";
 77→        break;
 78→    }
 79→
 80→    if (type.includes("Chart")) {
 81→      baseClass += " widget-height-chart";
 82→    }
 83→    if ((isPhone || isMobile) && !rowHeight === "auto") baseClass = "h-[600px]"
 84→    if (type === "table") {
 85→      baseClass = "widget-height-table";
 86→    }
 87→    return baseClass;
 88→  };
 89→
 90→  const bodyHeight = type === "table" ? "fit-content" : getBodyHeightClass();
 91→
 92→  return (
 93→    <div
 94→      className={`widget-container shadow-large ${type} ${getBodyWidthClass()} ${getBodyHeightClass()} ${rowHeight === "auto" ? "" : "max-h-[1000px]"}`}
 95→      ref={widgetContainerRef}
 96→      id={id}
 97→      key={id}
 98→    >
 99→      <ErrorBoundary bodyHeight={bodyHeight}>
100→        <Widget
101→          {...props}
102→          key={`${id}-${windowWidth}-${windowHeight}-${props.pageId}`}
103→          bodyHeight={bodyHeight}
104→          windowWidth={windowWidth}
105→          widgetContainerRef={widgetContainerRef}
106→        />
107→      </ErrorBoundary>
108→    </div>
109→  );
110→}
111→
112→export default WidgetWrapper;
