 37→function formatCompactNumber(num: number): string {
 38→	if (num >= 1_000_000_000) return `${(num / 1_000_000_000).toFixed(1)}B`;
 39→	if (num >= 1_000_000) return `${(num / 1_000_000).toFixed(1)}M`;
 40→	if (num >= 1_000) return `${(num / 1_000).toFixed(1)}K`;
 41→	return num.toFixed(0);
