 49→interface ModelTokensChartProps {
 50→	data: ModelTokensTrendData[];
 51→}
 52→
 53→export function ModelTokensChart({ data }: ModelTokensChartProps) {
 54→	const { gridStroke } = useChartTheme();
 55→	const [hiddenSeries, setHiddenSeries] = useState<Set<string>>(new Set());
 56→	const toggleSeries = (key: string) =>
 57→		setHiddenSeries((prev) => {
 58→			const next = new Set(prev);
 59→			next.has(key) ? next.delete(key) : next.add(key);
 60→			return next;
 61→		});
 62→
 63→	const { chartData, models } = useMemo(() => {
 64→		if (data.length === 0) return { chartData: [], models: [] };
 65→
 66→		// Compute total tokens per model to determine top 14
 67→		const modelTotals = new Map<string, number>();
 68→		for (const row of data) {
 69→			modelTotals.set(
 70→				row.model,
 71→				(modelTotals.get(row.model) ?? 0) + row.total_tokens,
 72→			);
 73→		}
 74→
 75→		const sortedModels = Array.from(modelTotals.entries()).sort(
 76→			(a, b) => b[1] - a[1],
 77→		);
 78→		const topModels = sortedModels.slice(0, MAX_SERIES).map(([m]) => m);
 79→		const topModelsSet = new Set(topModels);
 80→		const hasOther = sortedModels.length > MAX_SERIES;
 81→		const modelList = hasOther ? [...topModels, "Other"] : topModels;
 82→
 83→		// Build per-date raw data, bucketing overflow into "Other"
 84→		const rawByDate = new Map<string, Record<string, number>>();
 85→		for (const row of data) {
 86→			const entry = rawByDate.get(row.date) ?? {};
 87→			const key = topModelsSet.has(row.model) ? row.model : "Other";
 88→			entry[key] = (entry[key] ?? 0) + row.total_tokens;
 89→			rawByDate.set(row.date, entry);
 90→		}
 91→
 92→		// Build full date range so zero-value days are included
 93→		const allDates = Array.from(new Set(data.map((r) => r.date))).sort();
 94→		const minDate = new Date(allDates[0]);
 95→		const maxDate = new Date(allDates[allDates.length - 1]);
 96→		const dateRange: string[] = [];
 97→		for (let d = new Date(minDate); d <= maxDate; d.setDate(d.getDate() + 1)) {
 98→			dateRange.push(d.toISOString().split("T")[0]);
 99→		}
100→
101→		const sorted = dateRange.map((dateKey) => {
102→			const entry: Record<string, number | string> = {
103→				date: new Date(dateKey).toLocaleDateString("en-US", {
104→					month: "short",
105→					day: "numeric",
106→				}),
107→				_sort: dateKey,
108→			};
109→			const raw = rawByDate.get(dateKey) ?? {};
110→			for (const model of modelList) {
111→				entry[model] = raw[model] ?? 0;
112→			}
113→			return entry;
114→		});
115→
116→		return { chartData: sorted, models: modelList };
117→	}, [data]);
118→
119→	if (chartData.length === 0) return null;
120→
121→	return (
122→		<ResponsiveContainer width="100%" height={400}>
123→			<BarChart
124→				data={chartData}
125→				margin={{ top: 5, right: 0, left: 20, bottom: 5 }}
126→			>
127→				<CartesianGrid strokeDasharray="3 3" stroke={gridStroke} />
